import{_ as t,o,c as e,a2 as n}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"G14: 新業務展望","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/經營組備份_20260501/G14_新業務展望_產品趨勢研究員.md","filePath":"32Ｑ題本＿重要/經營組備份_20260501/G14_新業務展望_產品趨勢研究員.md"}'),s={name:"32Ｑ題本＿重要/經營組備份_20260501/G14_新業務展望_產品趨勢研究員.md"};function l(i,r,a,g,c,d){return o(),e("div",null,[...r[0]||(r[0]=[n('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="g14-新業務展望" tabindex="-1">G14: 新業務展望 <a class="header-anchor" href="#g14-新業務展望" aria-label="Permalink to &quot;G14: 新業務展望&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-G14</li><li><strong>題目：</strong> 公司在最近三年中是否有增加新的業務展望或第二成長曲線？其技術儲備與市場佈局進度為何？</li><li><strong>推薦專家：</strong> 產品趨勢研究員 (<code>product-trend-researcher</code>)</li><li><strong>推薦理由：</strong> 專注於行業趨勢分析與技術前瞻。擅長辨識「第二成長曲線」的真實爆發力，能從全球產業演進的角度，判定公司新增業務是順應未來 3-5 年的趨勢風口，還是進入過度飽和的夕陽市場，識別「無效轉型」風險。</li><li><strong>意圖：</strong> 鑑定業務邊界的擴張能力與未來獲利天花板。判定其新業務是否具備實質的競爭門檻，識別其在「研發期」、「樣品送審期」或「放量期」的具體位置。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【趨勢對位核心：IDC / Gartner / 專業智庫報告】</strong>：獲取標的新業務所屬產業的「未來年複合成長率 (CAGR)」與市場規模 (TAM)。</li><li><strong>【展望事實來源：Annual Report (年報)】</strong>：必須查閱 <code>業務概況 -&gt; 未來計畫</code>。提取管理層對新產品線或新市場的具體描述。</li><li><strong>【穿透校準：MOPS】</strong>：檢索「重大收購」、「董事會決議重要資本支出」或「重要契約簽訂」公告。</li><li><strong>【外部驗證：產品官方頁面 (New Products Launch)】</strong>：核實新產品是否已正式掛載官網或獲得相關技術認證。</li></ol></li><li><strong>邏輯：</strong> 執行「趨勢對位審計」——分析新業務是否具備較高的成長增速，並驗證標的公司是否具備切入該賽道的技術門檻。</li><li><strong>來源：</strong> <code>公司法說會簡報 (未來佈局)</code>, <code>產業趨勢報告 (Trend Reports)</code>, <code>專業機構市調數據</code>, <code>官方網站新產品分類</code></li></ul><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【賽道趨勢對位】</strong>：智慧體<strong>必須</strong>檢索該新業務所處產業的未來前景。針對新賽道，<strong>強制列出其未來 5 年之市場規模 (TAM) 預測與年複合成長率 (CAGR)</strong>。若新業務進入的是紅海競爭或夕陽產業，必須在評級中給予警示。</li><li><strong>【早期信號捕獲與 Design-win】</strong>：智慧體<strong>必須</strong>檢索標的公司在新領域是否已取得「Design-win (設計贏取)」或「官方認證/樣品測試通過」之實質信號。若僅停留在「規劃階段」而無具體料號或驗證公告，必須下調評級。</li><li><strong>【描述指標】</strong>：絕對禁用「轉型成功」、「展望樂觀」。必須量化為具體的「新業務預計貢獻佔比」、「目標市場規模 (USD)」與「技術認證取得進度」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【g14-專家答詢】產品趨勢研究員-product-trend-researcher" tabindex="-1">【G14 專家答詢】產品趨勢研究員 (product-trend-researcher) <a class="header-anchor" href="#【g14-專家答詢】產品趨勢研究員-product-trend-researcher" aria-label="Permalink to &quot;【G14 專家答詢】產品趨勢研究員 (product-trend-researcher)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：直接判定其新業務展望是「符合大勢、具備爆發潛力」、「合理補強、但增速有限」還是「錯誤轉型、進入紅海」。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：新業務位於高速成長賽道，且公司具備顯著的切入優勢（技術或通路），已有指標性訂單或 Design-win 實績。</li><li><strong>A (良)</strong>：戰略方向正確，處於市場回報初期，技術研發進度符合預期，具備穩健的擴張潛力。</li><li><strong>B (持平)</strong>：新業務與現有趨勢背離，或進入門檻極高且公司缺乏核心競爭力，轉型進度滯後且缺乏明確亮點。</li><li><strong>【答詢詳解】解析深度</strong>：必須嚴格遵守 Fact-First 原則，確保每一段論述都有物理數字實體支撐，嚴禁脫離數據空泛推論。</li><li><strong>【專家評析】核心洞察</strong>：必須啟用「華爾街空頭視角（Skepticism）」，強制演練最極端之風險阻力，並給出物理對策。</li></ul></li><li><strong>【證據來源】數據溯源</strong>：列出市場研究報告數據、新業務公告、或法說會具體展望頁碼。</li><li><strong>【專家建議】注意事項</strong>：提示投資人關注「該技術領域是否可能被新科技迅速取代」的顛覆性風險。</li></ul>',9)])])}const h=t(s,[["render",l]]);export{u as __pageData,h as default};
